// Code pour node n8n - Division de texte pour Discord
// Limite Discord : 2000 caractères par message

const DISCORD_CHAR_LIMIT = 2000;
const SAFETY_MARGIN = 50; // Marge de sécurité pour éviter les dépassements
const EFFECTIVE_LIMIT = DISCORD_CHAR_LIMIT - SAFETY_MARGIN;

function splitTextForDiscord(text) {
  // Si le texte est plus court que la limite, on le retourne tel quel
  if (text.length <= EFFECTIVE_LIMIT) {
    return [text];
  }

  const messages = [];
  let currentMessage = '';

  // Diviser le texte en paragraphes d'abord (séparés par \n\n ou ----)
  const sections = text.split(/(?:\n\n|----)/);

  for (let i = 0; i < sections.length; i++) {
    let section = sections[i].trim();

    // Si une section complète dépasse la limite, la diviser par phrases
    if (section.length > EFFECTIVE_LIMIT) {
      const sentences = section.split(/(?<=[.!?:])\s+/);

      for (const sentence of sentences) {
        // Si une phrase seule dépasse la limite, la couper brutalement
        if (sentence.length > EFFECTIVE_LIMIT) {
          const chunks = splitByLength(sentence, EFFECTIVE_LIMIT);
          for (const chunk of chunks) {
            if (currentMessage.length + chunk.length + 1 > EFFECTIVE_LIMIT) {
              if (currentMessage.trim()) {
                messages.push(currentMessage.trim());
              }
              currentMessage = chunk;
            } else {
              currentMessage += (currentMessage ? ' ' : '') + chunk;
            }
          }
        } else {
          // Ajouter la phrase si elle rentre dans le message actuel
          if (currentMessage.length + sentence.length + 1 <= EFFECTIVE_LIMIT) {
            currentMessage += (currentMessage ? ' ' : '') + sentence;
          } else {
            // Sauvegarder le message actuel et commencer un nouveau
            if (currentMessage.trim()) {
              messages.push(currentMessage.trim());
            }
            currentMessage = sentence;
          }
        }
      }
    } else {
      // La section rentre dans la limite, vérifier si elle rentre dans le message actuel
      if (currentMessage.length + section.length + 2 <= EFFECTIVE_LIMIT) {
        currentMessage += (currentMessage ? '\n\n' : '') + section;
      } else {
        // Sauvegarder le message actuel et commencer un nouveau
        if (currentMessage.trim()) {
          messages.push(currentMessage.trim());
        }
        currentMessage = section;
      }
    }
  }

  // Ajouter le dernier message s'il existe
  if (currentMessage.trim()) {
    messages.push(currentMessage.trim());
  }

  return messages.length > 0 ? messages : [text];
}

function splitByLength(text, maxLength) {
  const chunks = [];
  for (let i = 0; i < text.length; i += maxLength) {
    chunks.push(text.slice(i, i + maxLength));
  }
  return chunks;
}

// Code principal pour n8n
const inputData = $input.all();
const outputItems = [];

for (let i = 0; i < inputData.length; i++) {
  const item = inputData[i];

  // Extraire le texte à diviser (adaptez selon votre structure de données)
  // Exemple : si votre texte est dans item.json.content
  let textToSplit = '';

  // Si c'est un tableau comme dans votre exemple
  if (item.json.data && Array.isArray(item.json.data)) {
    textToSplit = item.json.data.map(dataItem => dataItem.text || '').join('\n\n---\n\n');
  } 
  // Si c'est directement du texte
  else if (item.json.text) {
    textToSplit = item.json.text;
  }
  // Si c'est dans un autre champ
  else if (item.json.content) {
    textToSplit = item.json.content;
  }
  // Fallback : convertir tout l'objet en texte
  else {
    textToSplit = JSON.stringify(item.json, null, 2);
  }

  // Diviser le texte
  const messages = splitTextForDiscord(textToSplit);

  // Créer un item de sortie pour chaque message
  messages.forEach((message, index) => {
    outputItems.push({
      json: {
        message: message,
        messageIndex: index + 1,
        totalMessages: messages.length,
        characterCount: message.length,
        originalItemIndex: i
      }
    });
  });
}

return outputItems;

const inputData = $input.all()[0].json;
const newsResults = inputData.news_results || [];

const sortedResults = newsResults.sort((a, b) => a.position - b.position);
const top3 = sortedResults.slice(0, 3);

return top3.map(item => ({
  json: {
    link: item.link || null,
    date: item.date || null
  }
}));

const items = $input.all();

function cleanMarkdown(text) {
  if (!text) return '';

  let cleaned = text;

  cleaned = cleaned.replace(/passer au contenu principal/gi, '');
  cleaned = cleaned.replace(/aller au contenu/gi, '');
  cleaned = cleaned.replace(/\[([^\]]+)\]\([^\)]+\)/g, '$1');
  cleaned = cleaned.replace(/\[([^\]]+)\]/g, '$1');
  cleaned = cleaned.replace(/https?:\/\/[^\s)]+/g, '');
  cleaned = cleaned.replace(/www\.[^\s)]+/g, '');
  cleaned = cleaned.replace(/\([^)]*(?:http|www)[^)]*\)/g, '');
  cleaned = cleaned.replace(/  +/g, ' ');
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n');
  cleaned = cleaned.split('\n').map(line => line.trim()).join('\n');
  cleaned = cleaned.trim();

  return cleaned;
}

const links = $('Extract Article URLs').all();

return items.map((item, index) => ({
  json: {
    link: links[index]?.json.link || null,
    date: links[index]?.json.date || null,
    markdown_clean: cleanMarkdown(item.json.data.markdown)
  }
}));
